sql:
SELECT dominant_feel
FROM computer_generations
WHERE begin_year = '1956';

SELECT dominant_feel
FROM computer_generations
WHERE generation_id = 1;

external_knowledge:
; The dominant look of a computer generation refers to the prevalent design or style of computers during that generation; 
; The average clock speed is a measure of the processor's speed, with higher values indicating faster processing capabilities; 
; Faster processor speeds generally correspond to better performance.

sql:
SELECT exhibit_name
FROM exhibits
WHERE exhibit_type = 'innovative';

SELECT COUNT(exhibit_id) 
FROM exhibits 
WHERE generation_id = (SELECT generation_id FROM computer_generations ORDER BY begin_year ASC LIMIT 1);
